function knowledgeGraphHTML(){const groups={数据结构:[["算法",50,12,"hot"],["排序",28,25,"core"],["查找",23,51,"core"],["图",24,75,"core"],["树与二叉树",52,78,"hot"],["线性表",76,27,"core"],["栈和队列",84,50,"hot"],["串",76,76,"core"]],组成原理:[["计算机系统概述",54,13,"core"],["数据的表示和运算",80,27,"core"],["存储系统",84,54,"hot"],["指令系统",62,75,"core"],["中央处理器",36,73,"core"],["总线",20,50,"core"],["I/O系统",29,27,"core"]],操作系统:[["进程管理",74,24,"core"],["处理机调度",88,41,"core"],["同步与互斥",80,70,"hot"],["内存管理",48,78,"core"],["文件管理",20,70,"core"],["输入/输出",13,43,"core"],["操作系统概述",40,20,"core"]],计算机网络:[["计算机网络体系结构",53,13,"core"],["物理层",82,26,"core"],["数据链路层",82,57,"hot"],["网络层",52,78,"core"],["传输层",21,64,"core"],["应用层",16,34,"core"]]};const children={数据结构:["顺序表","链表","队列","KMP","遍历","最短路径","二分查找","快速排序","堆排序","哈希表","并查集","B树"],组成原理:["补码","浮点数","存储芯片","Cache","虚拟存储器","寻址方式","流水线","中断","DMA","总线仲裁","磁盘"],操作系统:["进程状态","线程","调度算法","信号量","死锁","分页","页面置换","文件分配","磁盘调度","设备管理","I/O控制"],计算机网络:["OSI模型","TCP/IP","编码","差错控制","以太网","ARP","IP","路由算法","TCP","UDP","HTTP","DNS"]};const colors={数据结构:"#7da2e3",组成原理:"#d9b16f",操作系统:"#df9fbb",计算机网络:"#72c2a9"};return `<article class="card knowledge-graph-card"><div class="kg-toolbar"><div><h3>408 全局知识图谱</h3><p>按四科完整考纲展示知识点关系，可切换单科视图或总览。</p></div><div class="kg-tabs"><button class="active" data-graph-filter="all">总览</button>${Object.keys(groups).map(x=>`<button data-graph-filter="${x}">${x}</button>`).join("")}</div></div><div class="kg-actions"><button id="structureLayer" class="active">知识结构</button><button id="masteryLayer">叠加掌握状态</button><span id="layerNote">当前展示完整知识结构</span></div><div class="kg-canvas" id="knowledgeGraphCanvas">${Object.entries(groups).map(([subject,nodes],groupIndex)=>`<section class="kg-quadrant kg-q${groupIndex+1}" data-graph-group="${subject}" style="--kg-color:${colors[subject]}"><div class="kg-watermark">${subject}</div><svg class="kg-lines" viewBox="0 0 100 100" preserveAspectRatio="none">${nodes.map(n=>`<line x1="50" y1="50" x2="${n[1]}" y2="${n[2]}"></line>`).join("")}</svg><div class="kg-center">${subject}</div>${nodes.map((n,nodeIndex)=>`<button class="graph-point kg-node ${n[3]}" style="--x:${n[1]}%;--y:${n[2]}%" data-subject="${subject}" data-level="${n[3]==="hot"?"high":"key"}"><span>${n[0]}</span>${children[subject].slice(nodeIndex,nodeIndex+2).map((child,childIndex)=>`<i class="kg-child c${childIndex+1}">${child}</i>`).join("")}</button>`).join("")}</section>`).join("")}</div><div class="kg-legend"><span><i class="normal"></i>普通知识点</span><span><i class="important"></i>重点知识点</span><span><i class="weak"></i>个人薄弱点（叠加后显示）</span></div></article>`}
